mapper.select:
/* usimDlvryChnlMapper.getUsimDirDlvryChnlList */
SELECT SELF_DLVRY_IDX -- KT 오더 ID , KT_ORD_ID -- 배달업체 오더 ID , ORDER_STAT_CD -- 최초 배달 상태 코드 [cStateCode] , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'cStateCode' AND DTL_CD = A.ORDER_STAT_CD) AS ORDER_STAT_NM , ORDER_STAT_RSN_DESC -- 배달 상태 변경 상세 , BIZ_ORG_CD -- 배달업체 코드 , CSTMR_NAME -- 고객명 , FN_GET_CODENM('RCP9025', A.BIZ_ORG_CD) AS BIZ_ORG_NM , (DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN ) AS DLVRY_TEL , DLVRY_NAME -- 배송정보 이름 , DLVRY_POST -- 우편번호 , DLVRY_ADDR -- 기본주소 , DLVRY_ADDR_DTL -- 상세주소 , DLVRY_MEMO -- 배송메모 , CUST_INFO_AGREE_YN -- 개인정보제공동의 여부 , RSV_ORDER_YN -- 배달예약여부 , RSV_ORDER_DT -- 배달희망시간 , ORDER_REQ_MSG -- 배달요청메세지 , ENTY -- 고객 위치 좌표. decimal 형. 위도 (WGS84) , ENTX -- 고객 위치 좌표. decimal 형. 경도 (WGS84) , UNTACT -- 비대면 여부 , CHANNEL_CD -- 접수채널 [channel] , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'channel' AND DTL_CD = A.CHANNEL_CD) AS CHANNEL_NM , DLVRY_STATE_CODE -- 진행상태코드 , FN_GET_CODENM('RCP9024', DLVRY_STATE_CODE ) AS DLVRY_STATE_NM , SELF_STATE_CODE -- 신청상태코드 , FN_GET_CODENM('RCP9026', A.SELF_STATE_CODE) AS SELF_STATE_NM , TO_CHAR(A.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS') AS SYS_RDATE -- 등록일자 , DECODE(A.DLVRY_STATE_CODE, '04', (SELECT MAX(TO_CHAR(REGST_DTTM , 'YYYY-MM-DD HH24:MI:SS')) FROM MSP_DIRDVRY_USIM_HST WHERE KT_ORD_ID = A.KT_ORD_ID AND DLVRY_STATE_CODE = '04') ) AS CPL_DATE -- 완료일자 , NVL(PAY_CD, '01') AS PAY_CD -- 결제상태 , CASE WHEN PAY_CD IS NULL THEN '정상' ELSE FN_GET_CODENM('RCP9027', PAY_CD) END AS PAY_STATE , A.RE_ACCEPT_YN -- 재접수 여부 , A.RE_BIZ_ORG_CD -- 재배달 업체 , A.SELF_MEMO -- 메모 , FN_GET_CODENM('RCP9025', A.RE_BIZ_ORG_CD) AS RE_BIZ_ORG_NM , A.RVISN_ID -- 수정자 , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MCP_REQUEST_NOW_DLVRY@DL_MCP A WHERE A.CHANNEL_CD IS NOT NULL
AND TO_CHAR(A.SYS_RDATE, 'YYYYMMDD') BETWEEN #{strtDt} AND #{endDt}
AND A.ORDER_STAT_CD = #{orderStatCd}
AND A.DLVRY_STATE_CODE = #{dvryStatCd}
AND A.CHANNEL_CD = #{channelCd}
AND PAY_CD = #{payCd}
AND A.CSTMR_NAME like '%' || #{searchVal} || '%'
AND (A.DLVRY_TEL_FN || A.DLVRY_TEL_MN || A.DLVRY_TEL_RN ) = #{searchVal}
AND A.KT_ORD_ID = #{searchVal}
ORDER BY SYS_RDATE DESC

/* usimDlvryChnlMapper.getUsimDlvryChnlListByExcel */ SELECT SELF_DLVRY_IDX -- KT 오더 ID , KT_ORD_ID -- 배달업체 오더 ID , ORDER_STAT_CD -- 최초 배달 상태 코드 [cStateCode] , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'cStateCode' AND DTL_CD = A.ORDER_STAT_CD) AS ORDER_STAT_NM , ORDER_STAT_RSN_DESC -- 배달 상태 변경 상세 , BIZ_ORG_CD -- 배달업체 코드 , CSTMR_NAME -- 고객명 , FN_GET_CODENM('RCP9025', BIZ_ORG_CD) AS BIZ_ORG_NM , (DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN ) AS DLVRY_TEL , DLVRY_NAME -- 배송정보 이름 , DLVRY_POST -- 우편번호 , DLVRY_ADDR -- 기본주소 , DLVRY_ADDR_DTL -- 상세주소 , (DLVRY_ADDR || ' ' || DLVRY_ADDR_DTL) AS DLVRY_POST_ADDR , DLVRY_MEMO -- 배송메모 , CUST_INFO_AGREE_YN -- 개인정보제공동의 여부 , RSV_ORDER_YN -- 배달예약여부 , RSV_ORDER_DT -- 배달희망시간 , ORDER_REQ_MSG -- 배달요청메세지 , ENTY -- 고객 위치 좌표. decimal 형. 위도 (WGS84) , ENTX -- 고객 위치 좌표. decimal 형. 경도 (WGS84) , UNTACT -- 비대면 여부 , CHANNEL_CD -- 접수채널 [channel] , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'channel' AND DTL_CD = A.CHANNEL_CD) AS CHANNEL_NM , DLVRY_STATE_CODE -- 진행상태코드 , FN_GET_CODENM('RCP9024' , DLVRY_STATE_CODE ) AS DLVRY_STATE_NM , SELF_STATE_CODE -- 신청상태코드 , FN_GET_CODENM('RCP9026' , SELF_STATE_CODE) AS SELF_STATE_NM , TO_CHAR(A.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS') AS SYS_RDATE -- 등록일자 , DECODE(A.DLVRY_STATE_CODE, '04', (SELECT MAX(TO_CHAR(REGST_DTTM , 'YYYY-MM-DD HH24:MI:SS')) FROM MSP_DIRDVRY_USIM_HST WHERE KT_ORD_ID = A.KT_ORD_ID AND DLVRY_STATE_CODE = '04') ) AS CPL_DATE -- 완료일자 , NVL(PAY_CD, '01') AS PAY_CD -- 결제상태 , CASE WHEN PAY_CD IS NULL THEN '정상' ELSE FN_GET_CODENM('RCP9027', PAY_CD) END AS PAY_STATE , A.RE_ACCEPT_YN -- 재접수 여부 , A.RE_BIZ_ORG_CD -- 재배달 업체 , A.SELF_MEMO -- 메모 , FN_GET_CODENM('RCP9025', A.RE_BIZ_ORG_CD) AS RE_BIZ_ORG_NM , A.RVISN_ID -- 수정자 , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MCP_REQUEST_NOW_DLVRY@DL_MCP A WHERE A.CHANNEL_CD IS NOT NULL
AND TO_CHAR(A.SYS_RDATE, 'YYYYMMDD') BETWEEN #{strtDt} AND #{endDt}
AND A.ORDER_STAT_CD = #{orderStatCd}
AND A.DLVRY_STATE_CODE = #{dvryStatCd}
AND A.CHANNEL_CD = #{channelCd}
AND PAY_CD = #{payCd}
AND A.CSTMR_NAME like '%' || #{searchVal} || '%'
AND (A.DLVRY_TEL_FN || A.DLVRY_TEL_MN || A.DLVRY_TEL_RN ) = #{searchVal}
AND A.KT_ORD_ID = #{searchVal}
ORDER BY SYS_RDATE DESC

mapper.update:
/* usimDlvryChnlMapper.updateUsimDirDlvryChnlInfo */
UPDATE	MCP_REQUEST_NOW_DLVRY@DL_MCP
SET	  	PAY_CD = #{payCd, jdbcType=VARCHAR}
        , SELF_MEMO   = #{selfMemo, jdbcType=VARCHAR}
        , RVISN_ID          = #{sessionUserId, jdbcType=VARCHAR}
        , RVISN_DTTM        = SYSDATE
WHERE	SELF_DLVRY_IDX      = #{selfDlvryIdx, jdbcType=VARCHAR}
